SYMPTOM_SUGGESTIONS = {
    "болит живот": ["УЗИ брюшной полости", "Приём гастроэнтеролога", "Общий анализ крови (ОАК)", "Биохимический анализ крови"],
    "температура": ["Общий анализ крови (ОАК)", "ПЦР COVID-19", "Приём терапевта"],
    "головная боль": ["Приём невролога", "МРТ головного мозга", "Общий анализ крови (ОАК)"],
    "сердце": ["ЭКГ", "Приём кардиолога", "Холестерин общий"],
    "горло": ["Приём ЛОР-врача", "Общий анализ крови (ОАК)", "ПЦР грипп A/B"],
}

def clean(text: str) -> str:
    text = (text or "").strip().lower().replace("ё", "е")
    return re.sub(r"\s+", " ", text)

def normalize_query(q: str) -> str:
    qn = clean(q)
    if qn in {"оак", "oak", "cbc"}:
        return "Общий анализ крови (ОАК)"
    best_name, best_score = q, 0
    for name, _cat, syns in SERVICE_CATALOG:
        for c in [name] + syns:
            s = fuzz.partial_ratio(qn, clean(c))
            if s > best_score:
                best_name, best_score = name, s
    return best_name if best_score >= 70 else q

def suggestions(q: str, limit: int = 10):
    qn = clean(q)
    if not qn:
        return [x[0] for x in SERVICE_CATALOG[:limit]]
    symptom_hits = []
    for symptom, recs in SYMPTOM_SUGGESTIONS.items():
        if fuzz.partial_ratio(qn, clean(symptom)) >= 75:
            symptom_hits.extend(recs)
    scored = []
    for name, _cat, syns in SERVICE_CATALOG:
        score = max(fuzz.partial_ratio(qn, clean(x)) for x in [name] + syns)
        if score >= 42:
            scored.append((score, name))
    names = symptom_hits + [n for _s, n in sorted(scored, reverse=True)]
    out = []
    for n in names:
        if n not in out:
            out.append(n)
    return out[:limit]
